        </div>
      </div>

      <CodePreviewer demo-name="demo-node-state" />
      <p class="ch-text">
        使用 <code>registerNodeStateHandler()</code> 注册自定义节点状态处理器。
      </p>

      <h3 class="ch-subsection__title">API 签名</h3>
      <div class="ch-code-block">
        <pre><code class="language-typescript">designer.registerNodeStateHandler(
  stateName: string,           // 状态名称（如 'custom-error'）
  handler: NodeStateHandler,   // 状态处理器对象
  override?: boolean          // 是否覆盖已有处理器（默认 true）
)

// NodeStateHandler 接口
interface NodeStateHandler {
  apply(node: Node, context: NodeStateContext): void    // 应用状态
  cleanup?(node: Node, context: NodeStateContext): void // 清理状态（可选）
}

// 上下文对象
interface NodeStateContext {
  config: CanvasConfig      // 画布配置
  graph: Graph              // Graph 实例
  manager: NodeStateManager // 状态管理器实例
  canConnect: boolean       // 是否允许连线
}</code></pre>
      </div>

      <h3 class="ch-subsection__title">示例：自定义错误状态</h3>
      <p class="ch-text">
        以下示例注册一个 <code>error</code> 状态，使节点显示红色边框和错误图标。
      </p>

      <div class="ch-code-block">
        <pre><code class="language-typescript">// 在 @ready 回调中注册
function handleReady(designer: FlowDesigner) {
  // 注册自定义错误状态
  designer.registerNodeStateHandler('error', {
    apply(node, context) {
      // 设置红色边框
      node.setAttrs({
        body: {
          stroke: '#ef4444',
          strokeWidth: 3,
        }
      })

      // 设置节点数据（用于显示错误图标）
      node.setData({
        ...node.getData(),
        hasError: true
      })
    },
    cleanup(node, context) {
      // 恢复默认样式
      node.setAttrs({
        body: {
          stroke: '#d9d9d9',
          strokeWidth: 1,
        }
      })

      // 清除错误标记
      node.setData({
        ...node.getData(),
        hasError: false
      })
    }
  })

  // 使用：设置节点为错误状态
  const node = graph.getCellById('node1')
  node.setData({ state: 'error' })
}</code></pre>
      </div>
    </section>

