      <CodePreviewer demo-name="demo-edge-state" />
      <p class="ch-text">
        使用 <code>registerEdgeStateHandler()</code> 注册自定义连线状态处理器。
      </p>

      <h3 class="ch-subsection__title">API 签名</h3>
      <div class="ch-code-block">
        <pre><code class="language-typescript">designer.registerEdgeStateHandler(
  stateName: string,           // 状态名称（如 'custom-active'）
  handler: EdgeStateHandler,   // 状态处理器对象
  override?: boolean          // 是否覆盖已有处理器（默认 true）
)

// EdgeStateHandler 接口
interface EdgeStateHandler {
  apply(edge: Edge, context: EdgeStateContext): void    // 应用状态
  cleanup?(edge: Edge, context: EdgeStateContext): void // 清理状态（可选）
}

// 上下文对象
interface EdgeStateContext {
  config: CanvasConfig      // 画布配置
  graph: Graph              // Graph 实例
  manager: EdgeStateManager // 状态管理器实例
}</code></pre>
      </div>

      <h3 class="ch-subsection__title">示例：自定义激活状态</h3>
      <p class="ch-text">
        以下示例注册一个 <code>active</code> 状态，使连线显示绿色加粗样式。
      </p>

      <div class="ch-code-block">
        <pre><code class="language-typescript">// 在 @ready 回调中注册
function handleReady(designer: FlowDesigner) {
  // 注册自定义激活状态
  designer.registerEdgeStateHandler('active', {
    apply(edge, context) {
      // 设置绿色加粗样式
      edge.setAttrs({
        line: {
          stroke: '#10b981',
          strokeWidth: 3,
          strokeDasharray: '5 5',
        }
      })
    },
    cleanup(edge, context) {
      // 恢复默认样式
      edge.setAttrs({
        line: {
          stroke: '#8f959e',
          strokeWidth: 1,
          strokeDasharray: 'none',
        }
      })
    }
  })

  // 使用：设置连线为激活状态
  const edge = graph.getCellById('edge1')
  edge.setData({ state: 'active' })
}</code></pre>
      </div>
