    <!-- 钩子函数处理节点/连线状态 -->
    <section id="hook-state-handler" class="ch-section">
      <h2 class="ch-section__title">8.4 钩子函数处理节点/连线状态</h2>
      <p class="ch-text">
        除了使用 <code>designer.registerNodeStateHandler()</code> 和 <code>designer.registerEdgeStateHandler()</code> 在 <code>@ready</code> 回调中注册状态处理器外，
        FlowDesigner 还提供了<strong>更便捷的 Props 钩子方式</strong>来自定义状态渲染器，无需手动调用注册方法。
      </p>

      <div class="ch-callout ch-callout--tip">
        <div class="ch-callout__icon">🎯</div>
        <div class="ch-callout__content">
          <p class="ch-callout__title">钩子函数的优势</p>
          <ul class="ch-callout__list">
            <li><strong>声明式配置</strong>：通过 Props 传递，更符合 Vue 组件的使用习惯</li>
            <li><strong>响应式更新</strong>：支持动态修改状态渲染器，自动重新注册</li>
            <li><strong>类型安全</strong>：完整的 TypeScript 类型定义和智能提示</li>
            <li><strong>统一管理</strong>：与其他 Props 配置放在一起，便于维护</li>
          </ul>
        </div>
      </div>
      <CodePreviewer demo-name="demo-state-renderers" />

      <h3 class="ch-subsection__title">更全面的edge-state-renderers / node-state-renderers示例</h3>
      <CodePreviewer demo-name="demo-state-svgNode" />

      <h3 class="ch-subsection__title">节点状态渲染器 Props</h3>
      <p class="ch-text">
        使用 <code>:node-state-renderers</code> Props 传递节点状态渲染器映射表。
      </p>

      <div class="ch-code-block">
        <pre><code class="language-typescript">// Props 类型定义
interface NodeStateRendererMap {
  [stateName: string]: NodeStateRenderer
}

// 状态渲染器工厂函数
type NodeStateRenderer = (node: Node) => {
  apply: (cell: Node) => void      // 应用状态的函数
  cleanup?: (cell: Node) => void   // 清理状态的函数（可选）
}

// 使用示例
&lt;FlowDesignerLayout
  :node-state-renderers="nodeRenderers"
  @ready="handleReady"
/&gt;</code></pre>
      </div>

      <h3 class="ch-subsection__title">连线状态渲染器 Props</h3>
      <p class="ch-text">
        使用 <code>:edge-state-renderers</code> Props 传递连线状态渲染器映射表。
      </p>

      <div class="ch-code-block">
        <pre><code class="language-typescript">// Props 类型定义
interface EdgeStateRendererMap {
  [stateName: string]: EdgeStateRenderer
}

// 状态渲染器工厂函数
type EdgeStateRenderer = (edge: Edge) => {
  apply: (cell: Edge) => void      // 应用状态的函数
  cleanup?: (cell: Edge) => void   // 清理状态的函数（可选）
}

// 使用示例
&lt;FlowDesignerLayout
  :edge-state-renderers="edgeRenderers"
  @ready="handleReady"
/&gt;</code></pre>
      </div>

      <h3 class="ch-subsection__title">完整示例：动态状态渲染器</h3>
      <p class="ch-text">
        以下示例展示如何使用 Props 方式定义可动态切换的状态渲染器：
      </p>

      <div class="ch-code-block">
        <pre><code class="language-typescript">import { ref, computed } from 'vue'
import type { NodeStateRendererMap, EdgeStateRendererMap } from '@/types/render'
import type { Node, Edge } from '@antv/x6'

// 定义开关状态
const useCustomStyles = ref(true)

// 定义自定义节点状态渲染器
const customNodeRenderers: NodeStateRendererMap = {
  // 覆盖内置 hover 状态
  hover: (node: Node) => ({
    apply: (cell) => {
      cell.setAttrs({
        body: {
          stroke: '#8b5cf6',
          strokeWidth: 3,
          fill: '#ede9fe',
        }
      })
    }
  }),

  // 新增自定义 error 状态
  error: (node: Node) => ({
    apply: (cell) => {
      cell.setAttrs({
        body: {
          stroke: '#ef4444',
          strokeWidth: 3,
          strokeDasharray: '5,5'
        }
      })
    },
    cleanup: (cell) => {
      cell.setAttrs({
        body: {
          strokeDasharray: ''
        }
      })
    }
  })
}

// 定义自定义连线状态渲染器
const customEdgeRenderers: EdgeStateRendererMap = {
  // 覆盖内置 flowing 状态
  flowing: (edge: Edge) => ({
    apply: (cell) => {
      cell.attr({
        line: {
          stroke: '#10b981',
          strokeWidth: 3,
          strokeDasharray: '10,5',
          style: {
            animation: 'fd-flow 1s linear infinite'
          }
        }
      })
    },
    cleanup: (cell) => {
      cell.setAttrs({
        line: {
          strokeDasharray: '',
          style: { animation: 'none' }
        }
      })
    }
  })
}

// 使用 computed 实现动态切换
const computedNodeRenderers = computed(() => {
  return useCustomStyles.value ? customNodeRenderers : undefined
})

const computedEdgeRenderers = computed(() => {
  return useCustomStyles.value ? customEdgeRenderers : undefined
})</code></pre>
      </div>

      <div class="ch-code-block">
        <pre><code class="language-vue">&lt;template&gt;
  &lt;div&gt;
    &lt;!-- 开关控制 --&gt;
    &lt;label&gt;
      &lt;input type="checkbox" v-model="useCustomStyles" /&gt;
      使用自定义状态样式
    &lt;/label&gt;

    &lt;!-- FlowDesigner 组件 --&gt;
    &lt;FlowDesignerLayout
      :node-state-renderers="computedNodeRenderers"
      :edge-state-renderers="computedEdgeRenderers"
      @ready="handleReady"
    /&gt;
  &lt;/div&gt;
&lt;/template&gt;</code></pre>
      </div>

      <div class="ch-callout ch-callout--info">
        <div class="ch-callout__icon">ℹ️</div>
        <div class="ch-callout__content">
          <p class="ch-callout__title">渲染器函数调用时机</p>
          <ul class="ch-callout__list">
            <li><strong>工厂函数</strong>：当状态需要应用时调用，传入 node/edge 实例，返回 { apply, cleanup } 对象</li>
            <li><strong>apply 函数</strong>：立即执行，用于设置状态样式</li>
            <li><strong>cleanup 函数</strong>：当状态切换时自动调用（如果定义了），用于清理副作用</li>
            <li><strong>响应式更新</strong>：当 Props 变化时（如 computed 返回值改变），会自动重新注册所有状态处理器</li>
          </ul>
        </div>
      </div>

