<script setup lang="ts">
import { onMounted, ref } from 'vue'
import GuideLayout from '../components/GuideLayout.vue'
import CodePreviewer from '../components/CodePreviewer.vue'

// 滚动容器引用
const scrollContainer = ref<HTMLElement | null>(null)

onMounted(() => {
  // 获取滚动容器
  scrollContainer.value = document.querySelector('.guide-content')
  
  // 处理 URL hash
  const hash = window.location.hash
  if (hash) {
    const sectionId = hash.slice(1)
    setTimeout(() => scrollToSection(sectionId), 100)
  }
})

/**
 * 滚动到指定的章节
 */
function scrollToSection(sectionId: string) {
  const section = document.getElementById(sectionId)
  const container = scrollContainer.value
  
  if (!section || !container) {
    console.warn(`Section or container not found: ${sectionId}`)
    return
  }
  
  // 计算相对于滚动容器的偏移量
  const containerRect = container.getBoundingClientRect()
  const sectionRect = section.getBoundingClientRect()
  const offset = sectionRect.top - containerRect.top + container.scrollTop - 20
  
  // 滚动到目标位置
  container.scrollTo({
    top: offset,
    behavior: 'smooth'
  })
  
  // 更新 URL hash（不触发页面跳转）
  history.replaceState(null, '', `#${sectionId}`)
}
</script>

